// Strips invalid-for-Pages fields from all wrangler.json files generated by @astrojs/cloudflare
import { readFileSync, writeFileSync } from 'fs';

const FIELDS_TO_DELETE = [
  'main', 'rules', 'no_bundle', 'jsx_factory', 'jsx_fragment',
  'triggers', 'migrations', 'images', 'assets', 'previews'
];

function patchFile(path) {
  try {
    const config = JSON.parse(readFileSync(path, 'utf8'));
    config.kv_namespaces = (config.kv_namespaces ?? []).filter(kv => kv.binding !== 'SESSION');
    for (const key of FIELDS_TO_DELETE) delete config[key];
    writeFileSync(path, JSON.stringify(config));
    console.log(`[patch-wrangler] Cleaned: ${path}`);
  } catch {
    console.log(`[patch-wrangler] Skipped (not found): ${path}`);
  }
}

// Patch all known locations the adapter may write to
patchFile('dist/server/wrangler.json');
patchFile('dist/server/.prerender/wrangler.json');